import SwiftUI

struct Stock: Identifiable {
    let id = UUID()
    let symbol: String
    let price: Double
}

struct StockTickerView: View {
    @State private var stocks: [Stock] = [
        Stock(symbol: "AAPL", price: 180.0),
        Stock(symbol: "GOOG", price: 2700.0)
    ]
    var body: some View {
        TimelineView(.periodic(from: .now, by: 1)) { context in
            List(stocks) { stock in
                HStack {
                    Text(stock.symbol)
                    Spacer()
                    Text(String(format: "$%.2f", stock.price))
                }
            }
            .performanceSensitive()
        }
    }
}

import SwiftUI

struct WaveformView: View {
    @State private var amplitudes: [CGFloat] = Array(repeating: 0.5, count: 100)
    var body: some View {
        Canvas { context, size in
            let path = Path { p in
                p.move(to: .zero)
                for (i, amp) in amplitudes.enumerated() {
                    let x = size.width * CGFloat(i) / CGFloat(amplitudes.count - 1)
                    let y = size.height * (1 - amp)
                    p.addLine(to: CGPoint(x: x, y: y))
                }
            }
            context.stroke(path, with: .color(.blue), lineWidth: 2)
        }
        .performanceSensitive()
    }
}

