import SwiftUI

struct AnimatedCircleView: View {
    var body: some View {
        TimelineView(.animation) { context in
            Canvas { ctx, size in
                let t = context.date.timeIntervalSinceReferenceDate
                let x = size.width / 2 + cos(t * 2) * 50
                let y = size.height / 2 + sin(t * 2) * 50
                ctx.fill(Path(ellipseIn: CGRect(x: x, y: y, width: 30, height: 30)), with: .color(.red))
            }
        }
        .performanceSensitive()
    }
}

import SwiftUI

struct Item: Identifiable {
    let id = UUID()
    let name: String
    let value: Int
}

struct FilteredListView: View {
    @State private var items: [Item] = (0..<1000).map { Item(name: "Item \($0)", value: $0) }
    @State private var filter: String = ""
    var body: some View {
        VStack {
            TextField("Filter", text: $filter)
            List(filteredItems) { item in
                Text(item.name)
            }
            .performanceSensitive()
        }
    }
    var filteredItems: [Item] {
        items.filter { filter.isEmpty || $0.name.contains(filter) }
            .sorted { $0.value < $1.value }
    }
}

import SwiftUI

struct LargeChartView: View {
    let data: [CGFloat] = (0..<2000).map { _ in CGFloat.random(in: 0...1) }
    var body: some View {
        Canvas { context, size in
            let path = Path { p in
                p.move(to: .zero)
                for (i, y) in data.enumerated() {
                    let x = size.width * CGFloat(i) / CGFloat(data.count - 1)
                    p.addLine(to: CGPoint(x: x, y: size.height * (1 - y)))
                }
            }
            context.stroke(path, with: .color(.green), lineWidth: 1)
        }
        .performanceSensitive()
    }
}

import SwiftUI
import CoreMotion

class MotionManager: ObservableObject {
    private let manager = CMMotionManager()
    @Published var pitch: Double = 0
    init() {
        manager.deviceMotionUpdateInterval = 0.02
        manager.startDeviceMotionUpdates(to: .main) { [weak self] motion, _ in
            self?.pitch = motion?.attitude.pitch ?? 0
        }
    }
}

struct MotionView: View {
    @StateObject var motion = MotionManager()
    var body: some View {
        Text(String(format: "Pitch: %.2f", motion.pitch))
            .performanceSensitive()
    }
}

