        }
        .performanceSensitive()
    }
}

import SwiftUI

struct AnalogClockView: View {
    var body: some View {
        TimelineView(.animation) { context in
            Canvas { ctx, size in
                let center = CGPoint(x: size.width / 2, y: size.height / 2)
                let radius = min(size.width, size.height) / 2 - 10
                let date = context.date
                let calendar = Calendar.current
                let hour = CGFloat(calendar.component(.hour, from: date))
                let minute = CGFloat(calendar.component(.minute, from: date))
                let second = CGFloat(calendar.component(.second, from: date))
                // Draw clock face
                ctx.stroke(Path(ellipseIn: CGRect(x: 10, y: 10, width: size.width-20, height: size.height-20)), with: .color(.gray), lineWidth: 4)
                // Draw hour hand
                let hourAngle = Angle.degrees((hour + minute/60) * 30 - 90)
                let hourHand = CGPoint(x: center.x + cos(hourAngle.radians) * radius * 0.5, y: center.y + sin(hourAngle.radians) * radius * 0.5)
                ctx.stroke(Path { p in p.move(to: center); p.addLine(to: hourHand) }, with: .color(.black), lineWidth: 6)
                // Draw minute hand
                let minuteAngle = Angle.degrees((minute + second/60) * 6 - 90)
                let minuteHand = CGPoint(x: center.x + cos(minuteAngle.radians) * radius * 0.8, y: center.y + sin(minuteAngle.radians) * radius * 0.8)
                ctx.stroke(Path { p in p.move(to: center); p.addLine(to: minuteHand) }, with: .color(.black), lineWidth: 4)
                // Draw second hand
                let secondAngle = Angle.degrees(second * 6 - 90)
                let secondHand = CGPoint(x: center.x + cos(secondAngle.radians) * radius * 0.9, y: center.y + sin(secondAngle.radians) * radius * 0.9)
                ctx.stroke(Path { p in p.move(to: center); p.addLine(to: secondHand) }, with: .color(.red), lineWidth: 2)
            }
        }
        .performanceSensitive()
    }
}

import SwiftUI
import Combine

class SensorPublisher: ObservableObject {
    @Published var value: Double = 0
    private var timer: AnyCancellable?
    init() {
        timer = Timer.publish(every: 0.01, on: .main, in: .common).autoconnect().sink { [weak self] _ in
            self?.value = Double.random(in: 0...100)
        }
    }
}

struct SensorView: View {
    @StateObject var sensor = SensorPublisher()
    var body: some View {
        Text(String(format: "Sensor: %.2f", sensor.value))
            .performanceSensitive()
    }
}
